// === ThumbJoy 3-Wire Bridge вҖ” ATtiny85 Grip Firmware ===
// Reads 2 Melexis analog channels, sends via I2C to Teensy
// I2C Slave address: 0x27
// Sends 4 bytes: [CH1_HIGH, CH1_LOW, CH2_HIGH, CH2_LOW]

#include <TinyWireS.h>

#define I2C_ADDR 0x27
#define MEL_CH1  A3   // PB3, pin 2 вҖ” Melexis output 1
#define MEL_CH2  A2   // PB4, pin 3 вҖ” Melexis output 2

volatile uint16_t ch1_val = 512;
volatile uint16_t ch2_val = 512;

void setup() {
  pinMode(MEL_CH1, INPUT);
  pinMode(MEL_CH2, INPUT);
  TinyWireS.begin(I2C_ADDR);
  TinyWireS.onRequest(requestEvent);
}

void loop() {
  // Read both Melexis channels (10-bit ADC, 0вҖ“1023)
  ch1_val = analogRead(MEL_CH1);
  ch2_val = analogRead(MEL_CH2);
  TinyWireS_stop_check();  // Required for TinyWireS
  delay(5);  // ~200 Hz sample rate
}

// Called when Teensy requests data
void requestEvent() {
  uint8_t buf[4];
  buf[0] = (ch1_val >> 8) & 0xFF;  // CH1 high byte
  buf[1] = ch1_val & 0xFF;          // CH1 low byte
  buf[2] = (ch2_val >> 8) & 0xFF;  // CH2 high byte
  buf[3] = ch2_val & 0xFF;          // CH2 low byte
  for (int i = 0; i < 4; i++) {
    TinyWireS.send(buf[i]);
  }
}

