// === ALTERNATIVE: UART Version (even simpler) ===
// ATtiny85 sends 5-byte packet every 10ms via SoftwareSerial
// Format: [0xAA, CH1_H, CH1_L, CH2_H, CH2_L]

#include <SoftwareSerial.h>

#define TX_PIN 1    // PB1, pin 6
#define MEL_CH1 A3  // PB3, pin 2
#define MEL_CH2 A2  // PB4, pin 3

SoftwareSerial mySerial(-1, TX_PIN); // RX unused, TX only

void setup() {
  mySerial.begin(9600);
  pinMode(MEL_CH1, INPUT);
  pinMode(MEL_CH2, INPUT);
}

void loop() {
  uint16_t ch1 = analogRead(MEL_CH1);
  uint16_t ch2 = analogRead(MEL_CH2);

  mySerial.write(0xAA);            // Sync byte
  mySerial.write((ch1 >> 8) & 0xFF);
  mySerial.write(ch1 & 0xFF);
  mySerial.write((ch2 >> 8) & 0xFF);
  mySerial.write(ch2 & 0xFF);

  delay(10);  // 100 Hz
}

