// === Add to existing ThumbJoy Teensy firmware ===
// Replace direct analogRead of Melexis with I2C read from ATtiny85

#include <Wire.h>

#define GRIP_I2C_ADDR 0x27

uint16_t thumbwheel_ch1 = 512;
uint16_t thumbwheel_ch2 = 512;

void readThumbwheel() {
  Wire.requestFrom(GRIP_I2C_ADDR, 4);
  if (Wire.available() == 4) {
    uint8_t h1 = Wire.read();
    uint8_t l1 = Wire.read();
    uint8_t h2 = Wire.read();
    uint8_t l2 = Wire.read();
    thumbwheel_ch1 = (h1 << 8) | l1;  // 0вҖ“1023
    thumbwheel_ch2 = (h2 << 8) | l2;  // 0вҖ“1023
  }
}

// Call readThumbwheel() in your main loop instead of analogRead()
// thumbwheel_ch1 and thumbwheel_ch2 replace the old direct reads

