// === ALTERNATIVE: UART Version ===
// Teensy reads 5-byte packets from ATtiny85 on Serial2 (pin 7 = RX2)

void setup() {
  Serial2.begin(9600);  // RX2 = pin 7
}

void readThumbwheel() {
  while (Serial2.available() >= 5) {
    if (Serial2.read() == 0xAA) {  // Sync byte
      uint8_t h1 = Serial2.read();
      uint8_t l1 = Serial2.read();
      uint8_t h2 = Serial2.read();
      uint8_t l2 = Serial2.read();
      thumbwheel_ch1 = (h1 << 8) | l1;
      thumbwheel_ch2 = (h2 << 8) | l2;
    }
  }
}
